class APIGatewayClient:
    """
    gRPC client that acts as an API gateway, forwarding HTTP requests
    to backend gRPC services with proper metadata propagation.
    """

    def __init__(self, backend_address: str, default_timeout: float = 30.0,
                 use_tls: bool = False, ca_cert_path: str = None):
        self.backend_address = backend_address
        self.default_timeout = default_timeout

